// ============================================================
// 診断ロジック
// ============================================================
function calcResult(answers) {
  const sum = (type) =>
    QUESTIONS.filter((q) => q.type === type).reduce(
      (acc, q) => acc + (answers[q.id] || 0),
      0
    );
  const anxious = sum("anxious");
  const avoidant = sum("avoidant");
  const disorganized = sum("disorganized");
  const secure = sum("secure");

  let resultType;
  if (disorganized >= 17 && Math.abs(anxious - avoidant) <= 3) {
    resultType = "disorganized";
  } else if (anxious >= 14 && anxious - avoidant >= 4) {
    resultType = "anxious";
  } else if (avoidant >= 14 && avoidant - anxious >= 4) {
    resultType = "avoidant";
  } else if (secure >= 18 && anxious <= 13 && avoidant <= 13 && disorganized <= 13) {
    resultType = "secure";
  } else {
    // mixed: 最高スコアのタイプに寄せる
    const priority = ["disorganized", "anxious", "avoidant", "secure"];
    const scores = { anxious, avoidant, disorganized, secure };
    const max = Math.max(anxious, avoidant, disorganized, secure);
    resultType = priority.find((t) => scores[t] === max);
  }
  return { resultType, anxious, avoidant, disorganized, secure };
}

